import { StatusBar } from 'expo-status-bar';
// import { StyleSheet, Text, View } from 'react-native';

import { StyleSheet, Text, View, Dimensions, Image, Animated } from 'react-native';


const SCREEN_HEIGHT = Dimensions.get('window').height
const SCREEN_WIDTH = Dimensions.get('window').width

// export default function App() {
//   return (
//     <View style={styles.container}>
//       <Text>Hello!</Text>
//       <StatusBar style="auto" />
//     </View>
//   );
// }


export default function App() {
  return (
    <View style={{ flex: 1 }}>
        <View style={{ height: 60 }} />
        <View style={{ flex: 1 }}>
          <Animated.View
            style={[styles.cardView]}>
            <Image
              style={styles.image}
              source={Foods[1].uri}
            />
          </Animated.View>
        </View>
        <View style={{ height: 60 }} />
      </View>
  );
}


function renderFoods(){
  return Foods.map((item, i) => {
      return (
        <Animated.View
          style={{
            height: SCREEN_HEIGHT - 120,
            width: SCREEN_WIDTH,
            padding: 10
          }}
        >
          <Image
            style={{
              flex: 1,
              height: null,
              width: null,
              resizeMode: "cover",
              borderRadius: 20
            }}
            source={item.uri}
          />
        </Animated.View>
      );
   });

}






const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
    alignItems: 'center',
    justifyContent: 'center',
  },
  image: {
    flex: 1,
    height: null,
    width: null,
    resizeMode: "cover",
    borderRadius: 20
  },
  cardView:{
    height: SCREEN_HEIGHT - 120,
    width: SCREEN_WIDTH,
    padding: 10
  }
});


const Foods = [
  { id: "1", uri: require('./assets/img0.png') },
  { id: "2", uri: require('./assets/img1.jpeg') },
  { id: "3", uri: require('./assets/img2.png') },
  { id: "4", uri: require('./assets/img3.jpeg') },
  { id: "5", uri: require('./assets/img4.jpeg') },
]
